import React, {
    createContext,
    useContext,
    useEffect,
    useMemo,
    useRef,
    useState,
} from "react";
import DocumentPicker, { type DocumentPickerOptions } from "react-native-document-picker";
import { launchImageLibrary } from "react-native-image-picker";
import RNFS from "react-native-fs";

import {type IFileUploader, type File, type IMemes, toMemes} from "@lmb/kitsconcerto-types";
import { getType } from "@lmb/kitsconcerto-types";
import { Flex } from "../../../../";

import SingleFileUploader from "../SingleFileUploader";
import MultipleFileUploader from "../MultipleFileUploader";
import SingleImageUploader from "../SingleImageUploader";
import MultipleImageUploader from "../MultipleImageUploader";
import {AnyFile} from "../../../../../Utils";

type Base64Item = { filename: string; base64: string; type: string };

interface IFileUploaderContextValues {
    onChangeAnyFileUploader(files: File[]): void;
    onPick(): void;
    removeFile(fileIndex: number): () => void;
    onInvalidInput(errors: any): void;

    selectedFiles: File[];
    selectedInitialFiles: string[];

    placeholder?: string;
    disabled?: boolean;
    isClassicUploader: boolean;
    limit: number;
    acceptedMemes: string[]; // mime list
    files: { name: string; ext: string; shortName: string; file: { uri: string } | string }[];
    id: string;
    isImage: boolean;
}

export const FileUploaderContext = createContext<IFileUploaderContextValues>({
    onChangeAnyFileUploader: () => {
    },
    onPick: () => {},
    removeFile: () => () => {},
    onInvalidInput: () => {},
    disabled: false,
    limit: 1,
    isClassicUploader: true,
    selectedInitialFiles: [],
    selectedFiles: [],
    acceptedMemes: [],
    files: [],
    id: "",
    isImage: false,
});

const stripExt = (name: string) => name.replace(/\.[^/.]+$/, "");
const getExt = (name: string) => (name.split(".").pop() ?? "").toLowerCase();

const readFileAsBase64 = async (uri: string) => {
    // DocumentPicker returns fileCopyUri when copyTo is used; use that when possible
    // RNFS expects file paths without "file://"
    const path = uri.startsWith("file://") ? uri.replace("file://", "") : uri;
    return RNFS.readFile(path, "base64");
};

const MainUploader = (props: IFileUploader) => {
    const {
        acceptedTypes,
        type,
        classicUploader = true,
        limit = 1,
        onError,
        onFocus,
        placeholder,
        defaultValue,
        multiple,
        isJsonOutput = true,
        onChange,
        value,
        name,
        disabled,
        maxFileSize,
        minFileSize,
    } = props;

    const initialValueSynced = useRef(false);

    const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
    const [selectedInitialFiles, setSelectedInitialFiles] = useState<string[]>([]);
    const [selectedFilesAsBase64, setSelectedFilesAsBase64] = useState<Base64Item[]>([]);

    const isImage = type === "Image";
    const isOneFile = !multiple || limit < 2;

    const onInvalidInput = (err: any) => onError?.(err);

    const acceptedMemes = useMemo(() => {
        return acceptedTypes ? toMemes(acceptedTypes) : toMemes(['allFiles']);
    }, [acceptedTypes]);

    const validateSize = (sizeBytes?: number) => {
        if (!sizeBytes) return true;
        const sizeKB = sizeBytes / 1000;
        if (maxFileSize && sizeKB > maxFileSize) return false;
        return !(minFileSize && sizeKB < minFileSize);

    };

    const pickDocuments = async () => {
        try {
            const types:DocumentPickerOptions = {
                allowMultiSelection: !isOneFile,
                // copy to cache so we can read base64 reliably
                copyTo: "cachesDirectory",
                // DocumentPicker supports mime list; if empty let OS choose anything
                type: acceptedMemes.length ? acceptedMemes : [DocumentPicker.types.allFiles],
            }

            const res = await DocumentPicker.pick(types);

            const docs = (Array.isArray(res) ? res : [res]).map((d) => ({
                uri: (d.fileCopyUri || d.uri) as string,
                name: d.name || "file",
                type: d.type || undefined,
                size: d.size || undefined,
            }));

            const filtered = docs.filter((d) => {
                const ok = validateSize(d.size);
                if (!ok) {
                    onInvalidInput(`File "${d.name}" size is not allowed`);
                }
                return ok;
            });

            if (!filtered.length) return;
            setSelectedFiles((prev) => {
                if (isOneFile) {
                    const [first] = filtered;
                    return first ? [first] : prev;
                }
                return [...prev, ...filtered];
            });
            onInvalidInput("clear");
        } catch (e: any) {
            if (DocumentPicker.isCancel(e)) return;
            onInvalidInput(e);
        }
    };

    const pickImages = async () => {
        try {
            const res = await launchImageLibrary({
                mediaType: "photo",
                selectionLimit: isOneFile ? 1 : limit,
                includeBase64: true,
            });

            if (res.didCancel) return;
            if (res.errorCode) {
                onInvalidInput(res.errorMessage || res.errorCode);
                return;
            }

            const assets = res.assets || [];
            const mapped: File[] = assets
                .filter((a) => !!a.uri)
                .map((a) => ({
                    uri: a.uri!,
                    name: a.fileName || "image",
                    type: a.type || "image/jpeg",
                    size: a.fileSize,
                }))
                .filter((f) => {
                    const ok = validateSize(f.size);
                    if (!ok) onInvalidInput(`File "${f.name}" size is not allowed`);
                    return ok;
                });

            if (!mapped.length) return;

            setSelectedFiles((prev) => {
                if (isOneFile) {
                    const [first] = mapped;
                    return first ? [first] : prev;
                }
                return [...prev, ...mapped];
            });

            onInvalidInput("clear");

            // for images, we already have base64 in the picker response; store it immediately
            const b64: Base64Item[] = assets
                .filter((a) => !!a.base64)
                .map((a) => ({
                    filename: stripExt(a.fileName || "image"),
                    base64: a.base64!,
                    type: a.type || "image/jpeg",
                }));

            // keep order aligned with selectedFiles: for single this is OK; for multi, append
            setSelectedFilesAsBase64((prev) => (isOneFile ? b64.slice(0, 1) : [...prev, ...b64]));
        } catch (e: any) {
            onInvalidInput(e);
        }
    };

    const onChangeAnyFileUploader = (files: File[]) => {
        if (disabled) {
            return;
        }
        const filesList: any[] = [];

        setSelectedFilesAsBase64([]);
        for (let i = 0; i < files.length; i++) {
            const f = files[i];
            if (f) {
                // @ts-ignore
                const fileSize = f.size / 1000; // size in KB

                if ((!maxFileSize || fileSize <= maxFileSize) && (!minFileSize || fileSize >= minFileSize)) {
                    filesList.push(f);
                    onInvalidInput('clear')
                } else {
                    let message = `File "${f.name}" is `;

                    if (maxFileSize && fileSize > maxFileSize) {
                        message += `too large. Maximum allowed is ${maxFileSize/1000} MB.`;
                    } else if (minFileSize && fileSize < minFileSize) {
                        message += `too small. Minimum allowed is ${minFileSize/1000} MB.`;
                    }

                    console.log(message)
                    onInvalidInput(message);
                }
            }
        }

        if (!isOneFile) {
            setSelectedFiles(prevState => {
                return [...prevState, ...filesList];
            });
        } else {
            if (filesList.length)
                setSelectedFiles(filesList.slice(0, 1));
        }
    };
    const onPick = async () => {
        if (disabled) return;
        if (isImage) return pickImages();
        return pickDocuments();
    };

    const removeFile = (fileIndex: number) => () => {
        if (fileIndex < selectedInitialFiles.length) {
            setSelectedInitialFiles((prev) => prev.filter((_, i) => i !== fileIndex));
            return;
        }

        const editIndex = fileIndex - selectedInitialFiles.length;
        setSelectedFiles((prev) => prev.filter((_, i) => i !== editIndex));
        setSelectedFilesAsBase64((prev) => prev.filter((_, i) => i !== editIndex));
    };

    // Convert picked documents to base64 (images handled by picker includeBase64)
    useEffect(() => {
        if (isImage) return;

        const run = async () => {
            try {
                const next: Base64Item[] = [];
                for (const f of selectedFiles) {
                    // only for documents; images might not be readable via RNFS content URIs
                    const b64 = await readFileAsBase64(f.uri);
                    next.push({
                        filename: stripExt(f.name),
                        base64: b64,
                        type: f.type || getType(getExt(f.name) as any) || "application/octet-stream",
                    });
                }
                setSelectedFilesAsBase64(next);
            } catch (e) {
                onInvalidInput(e);
            }
        };

        run().then(r => {

        });
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedFiles, isImage]);

    // Emit onChange
    useEffect(() => {
        if (disabled) return;

        if (!selectedFiles.length && !selectedInitialFiles.length) {
            onChange?.([], []);
            return;
        }

        // Respect isJsonOutput (web behavior):
        // - when true: use base64Data output
        // - when false: still return picked files list (native file objects)
        // Output shape is platform-specific via types.native.ts
        if (isJsonOutput) {
            if (selectedFilesAsBase64.length === selectedFiles.length || isImage) {
                onChange?.(selectedFiles as any, selectedFilesAsBase64);
            }
        } else {
            onChange?.(selectedFiles as any, selectedFilesAsBase64);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedFilesAsBase64, selectedInitialFiles, selectedFiles]);

    // defaultValue + controlled value sync
    useEffect(() => {
        if (defaultValue) {
            setSelectedInitialFiles(Array.isArray(defaultValue) ? defaultValue : [defaultValue]);
        }
    }, [defaultValue]);

    useEffect(() => {
        if (initialValueSynced.current) return;
        if (value) {
            setSelectedInitialFiles(Array.isArray(value) ? value : [value]);
        }
        initialValueSynced.current = true;
    }, [value]);

    const display = useMemo(() => {
        const fromInitial = selectedInitialFiles.map((uri) => ({
            name: uri.split("/").pop() ?? uri,
            shortName:AnyFile.shortName(uri),
            ext: getExt(uri),
            file: { uri },
        }));

        const fromPicked = selectedFiles.map((f) => ({
            name: f.name,
            shortName:AnyFile.shortName(f.name),
            ext: getExt(f.name),
            file: { uri: f.uri },
        }));

        return [...fromInitial, ...fromPicked];
    }, [selectedFiles, selectedInitialFiles]);

    return (
        <FileUploaderContext.Provider
            value={{
                onChangeAnyFileUploader,
                onPick,
                removeFile,
                onInvalidInput,
                selectedFiles,
                selectedInitialFiles,
                disabled,
                limit,
                placeholder,
                isClassicUploader: classicUploader,
                acceptedMemes,
                files: display,
                id: name ?? "",
                isImage,
            }}
        >
            <Flex onFocus={onFocus as any} w={"full"} >
                {isImage && isOneFile && <SingleImageUploader />}
                {!isImage && isOneFile && <SingleFileUploader />}
                {!isImage && !isOneFile && <MultipleFileUploader />}
                {isImage && !isOneFile && <MultipleImageUploader />}
            </Flex>
        </FileUploaderContext.Provider>
    );
};

export default MainUploader;
export const useUploader = () => useContext(FileUploaderContext);
